const fs = require('fs');
const https = require('https');

https.get('https://api.urbnbox.com/api/vendor/v1/orders/csv-template', (res) => {
  res.pipe(fs.createWriteStream('urbnbox-orders-template.csv'));
  res.on('end', () => console.log('Template saved.'));
});

